UPDATE tb_predict_usage 
       
       
       std_timestamp = #{entity.stdTimestamp},
       
       
       pre_usg_val = #{entity.preUsgVal},
       
       mod_date = NOW(),
       
 WHERE pre_usg_idx = #{entity.preUsgIdx}

