mapper.select:
/* 사용량 상세조회ByUnique */
SELECT pre_usg_idx,
       site_id,
       device_id,
       std_timestamp,
       std_date,
       pre_usg_val,
       reg_date,
       mod_date
  FROM tb_predict_usage
 WHERE site_id = #{siteId}
   AND device_id = #{deviceId}
   AND std_timestamp = #{stdTimestamp}

/* 예측사용량 전체 개수 조회 */
SELECT COUNT(*) AS CNT
  FROM tb_predict_usage
 WHERE pre_usg_idx = #{preUsgIdx}
